ALGORITHM QuadraticModel(f, grad_f, H, xk, pk)
INPUT: f(x), gradient grad_f(x), Hessian H(x), current point xk, direction pk
OUTPUT: Quadratic model value m(pk)

BEGIN
 // Quadratic model: m(pk) = f(xk) + gradᵀpk + ½pkᵀHpk
 fk ← f(xk)
 gk ← grad_f(xk)
 Hk ← H(xk)

 // Linear term: gkᵀpk
 linear_term ← dot_product(gk, pk)

 // Quadratic term: ½pkᵀHpk
 Hpk ← matrix_vector_product(Hk, pk)
 quad_term ← 0.5 * dot_product(pk, Hpk)

 // Total quadratic approximation
 m_pk ← fk + linear_term + quad_term

 RETURN m_pk
END

ALGORITHM SolveTrustRegionSubproblem(f, grad, H, Delta)
// Find optimal step pk within trust radius Delta
BEGIN
 // Use Newton step or Cauchy point
 // pk = -H⁻¹g for full Newton
 // or pk = -(gᵀg / gᵀHg) * g for steepest descent
 // constrained to ||pk|| ≤ Delta
 RETURN pk
END
